public void fireBullet() {
    // Ensure we don't exceed the maximum bullets
    if (bullets.size() >= MAX_BULLETS) {
        return;
    }

    // Enforce firing interval
    long currentTime = System.currentTimeMillis();
    if (currentTime - bulletTime < BULLET_INTERVAL) {
        return;
    }
    bulletTime = currentTime;

    // Spawn position for the bullet
    float sx = xStartPos;
    float sy = yStartPos;
    float sz = zStartPos;

    // Compute velocity from heading and forward speed
    float vx = (float) Math.cos(heading) * MOVE_FORWARD_SPEED;
    float vy = 0f; // No vertical component by default
    float vz = (float) Math.sin(heading) * MOVE_FORWARD_SPEED;

    // Create and register the new bullet
    Bullet b = new Bullet(sx, sy, sz, vx, vy, vz);
    bullets.add(b);
}
